3	public final class UsagesFileManager: Sendable {
4	    public let filePath: String
5	    public let lockPath: String
6	    private let logger: FileLogger
7	
8	    public init(
9	        filePath: String? = nil,
10	        logger: FileLogger = Loggers.app
11	    ) {
12	        let home = FileManager.default.homeDirectoryForCurrentUser.path
13	        self.filePath = filePath ?? "\(home)/.cache/ai-usages-tracker/usages.json"
14	        self.lockPath = self.filePath + ".lock"
15	        self.logger = logger
16	
17	        let dir = (self.filePath as NSString).deletingLastPathComponent
18	        do {
19	            try FileManager.default.createDirectory(atPath: dir, withIntermediateDirectories: true, attributes: nil)
20	        } catch {
21	            logger.log(.error, "Failed to create directory \(dir): \(error)")
22	        }
23	    }
24	
25	    // MARK: - Public
26	
27	    public func read() -> UsagesFile {
28	        withFlockShared {
29	            readUnsafe()
30	        } ?? UsagesFile()
31	    }
32	
33	    public func update(with entries: [VendorUsageEntry]) {
34	        let success = withFlockExclusive {
35	            var file = readUnsafe()
36	            file = merge(existing: file, incoming: entries)
37	            writeUnsafe(file)
38	        }
39	        if !success {
40	            logger.log(.error, "update(with:) skipped — failed to acquire exclusive flock")
41	        }
42	    }
43	
44	    // MARK: - Merge logic
45	
46	    public func merge(existing: UsagesFile, incoming: [VendorUsageEntry]) -> UsagesFile {
47	        var usages = existing.usages
48	        var indexByKey: [String: Int] = [:]
49	        for (i, entry) in usages.enumerated() {
50	            indexByKey["\(entry.vendor)|\(entry.account)"] = i
51	        }
52	        for entry in incoming {
53	            let key = "\(entry.vendor)|\(entry.account)"
54	            if let idx = indexByKey[key] {
55	                usages[idx] = entry
56	            } else {
57	                indexByKey[key] = usages.count
58	                usages.append(entry)
59	            }
60	        }
61	        return UsagesFile(usages: usages)
62	    }
63	
64	    // MARK: - Unsafe (caller holds lock)
65	
66	    private func readUnsafe() -> UsagesFile {
67	        guard let data = FileManager.default.contents(atPath: filePath) else {
68	            return UsagesFile()
69	        }
70	        do {
71	            let decoder = JSONDecoder()
72	            return try decoder.decode(UsagesFile.self, from: data)
73	        } catch {
74	            logger.log(.error, "Failed to decode \(filePath): \(error)")
75	            return UsagesFile()
76	        }
77	    }
78	
79	    private func writeUnsafe(_ file: UsagesFile) {
80	        let encoder = JSONEncoder()
81	        encoder.outputFormatting = [.prettyPrinted, .sortedKeys]
82	        guard let data = try? encoder.encode(file) else {
83	            logger.log(.error, "Failed to encode usages file")
84	            return
85	        }
86	        do {
87	            try data.write(to: URL(fileURLWithPath: filePath), options: .atomic)
88	        } catch {
89	            logger.log(.error, "Atomic write failed: \(error)")
90	            return
91	        }
92	        logger.log(.debug, "Wrote usages file to \(filePath)")
93	    }
94	
95	    // MARK: - POSIX flock
96	
97	    private func withFlockShared<T>(_ body: () -> T) -> T? {
98	        withFlock(operation: LOCK_SH, body)
99	    }
100	
101	    @discardableResult
102	    private func withFlockExclusive(_ body: () -> Void) -> Bool {
103	        withFlock(operation: LOCK_EX, body) != nil
104	    }
105	
106	    private func withFlock<T>(operation: Int32, _ body: () -> T) -> T? {
107	        let fd = open(lockPath, O_RDWR | O_CREAT, 0o644)
108	        guard fd >= 0 else {
109	            logger.log(.error, "Cannot open lock file \(lockPath)")
110	            return nil
111	        }
112	        defer {
113	            flock(fd, LOCK_UN)
114	            close(fd)
115	        }
116	
117	        guard flock(fd, operation) == 0 else {
